INSERT INTO instructors (id, name, email, bio, avatar_url, specialty, years_experience, total_students, rating) VALUES
(1, 'Juan García López', 'juan@coderup.com', 'Experto en React y JavaScript moderno. 5 años en desarrollo frontend. Ha mentorizado a más de 2400 estudiantes. Apasionado por la arquitectura de componentes escalable, accesibilidad y rendimiento web.', 'https://i.pravatar.cc/150?img=1', 'React / Frontend', 5, 2400, 4.80),
(2, 'María López Rodríguez', 'maria@coderup.com', 'Especialista en backend con Node.js, PHP y bases de datos. 6 años en arquitectura de sistemas. Diseña APIs que sirven a millones de requests y acompaña a equipos en decisiones técnicas defendibles.', 'https://i.pravatar.cc/150?img=2', 'Node.js / Backend', 6, 3100, 4.90),
(3, 'Carlos Rodríguez Pérez', 'carlos@coderup.com', 'DevOps engineer con experiencia en Docker, Kubernetes y AWS. 7 años en infraestructura. Ha desplegado sistemas críticos en producción y domina CI/CD, observabilidad y automatización.', 'https://i.pravatar.cc/150?img=3', 'DevOps / Infraestructura', 7, 1800, 4.70),
(4, 'Ana Martínez García', 'ana@coderup.com', 'Diseñadora UI/UX con pasión por la experiencia de usuario. 4 años en diseño digital. Ha trabajado con startups y grandes empresas, con foco en accesibilidad y sistemas visuales.', 'https://i.pravatar.cc/150?img=4', 'Diseño UI/UX', 4, 900, 4.60);
