INSERT INTO courses (id, title, slug, description, thumbnail_url, price, level, category_id, instructor_id, duration_hours, total_lessons, total_students, rating, `requires`, what_you_learn, curriculum, is_published) VALUES
(1, 'React Avanzado', 'react-avanzado', 'Domina React al nivel profesional con hooks personalizados, context API, optimización de rendimiento y patrones de arquitectura escalable. Incluye proyectos reales para portfolio y criterios para defender decisiones frontend en entornos profesionales.', 'https://images.unsplash.com/photo-1633356122544-f134324ef6db?w=500', 49.99, 'Avanzado', 1, 1, 32, 48, 2400, 4.80, JSON_ARRAY('JavaScript ES6+', 'HTML y CSS', 'Conocimiento básico de React'), JSON_ARRAY('Hooks personalizados', 'Context API y useReducer', 'Optimización con memo', 'Testing con React Testing Library', 'TypeScript en React', 'Routing avanzado', 'State management', 'Componentes escalables'), JSON_OBJECT('modulos', JSON_ARRAY(JSON_OBJECT('nombre', 'Hooks Avanzados', 'lecciones', JSON_ARRAY('Custom Hooks', 'useReducer', 'useContext')), JSON_OBJECT('nombre', 'Optimización', 'lecciones', JSON_ARRAY('Code splitting', 'React.memo', 'Profiling')), JSON_OBJECT('nombre', 'Proyecto final', 'lecciones', JSON_ARRAY('E-commerce', 'Dashboard', 'Deploy')))), TRUE),
(2, 'Node.js & APIs REST', 'nodejs-apis-rest', 'Crea APIs robustas con autenticación, validación de datos, conexión a MySQL y patrones RESTful. Aprenderás middleware, error handling, paginación, seguridad y despliegue en producción.', 'https://images.unsplash.com/photo-1627398242454-45a570e2f320?w=500', 39.99, 'Intermedio', 2, 2, 28, 42, 3100, 4.90, JSON_ARRAY('JavaScript fundamentals', 'npm y Node.js básico', 'HTTP y REST'), JSON_ARRAY('Routing y middleware', 'Autenticación con JWT', 'Validación de entrada', 'MySQL con transacciones', 'Manejo de errores', 'Testing de APIs', 'Deploy cloud', 'Documentación'), JSON_OBJECT('modulos', JSON_ARRAY(JSON_OBJECT('nombre', 'Express Fundamentals', 'lecciones', JSON_ARRAY('Setup', 'Routing', 'Middleware')), JSON_OBJECT('nombre', 'Autenticación', 'lecciones', JSON_ARRAY('Hashing', 'Tokens', 'Roles')), JSON_OBJECT('nombre', 'Deployment', 'lecciones', JSON_ARRAY('Railway', 'Variables', 'Logs')))), TRUE),
(3, 'TypeScript Profesional', 'typescript-profesional', 'Lleva TypeScript al siguiente nivel con tipos avanzados, generics, utility types y modelado de estados. Ideal para proyectos grandes con contratos claros entre frontend y backend.', 'https://images.unsplash.com/photo-1516321318423-f06f70d504f0?w=500', 44.99, 'Intermedio', 1, 1, 24, 36, 1800, 4.70, JSON_ARRAY('JavaScript ES6+', 'TypeScript básico'), JSON_ARRAY('Tipos avanzados', 'Generics', 'Utility types', 'Type guards', 'DTOs de API', 'Modelado de dominio', 'Refactor seguro', 'Tipado de React'), JSON_OBJECT('modulos', JSON_ARRAY(JSON_OBJECT('nombre', 'Tipos Avanzados', 'lecciones', JSON_ARRAY('Union', 'Intersection', 'Narrowing')), JSON_OBJECT('nombre', 'Generics', 'lecciones', JSON_ARRAY('Funciones', 'Constraints', 'Componentes')), JSON_OBJECT('nombre', 'APIs', 'lecciones', JSON_ARRAY('DTO', 'Mappers', 'Errores')))), TRUE),
(4, 'Astro desde Cero', 'astro-desde-cero', 'Crea sitios ultra rápidos con Astro, islands architecture, rutas estáticas, contenido dinámico y despliegue en Vercel. Perfecto para blogs, documentación y plataformas de cursos.', 'https://images.unsplash.com/photo-1517694712202-14dd9538aa97?w=500', 34.99, 'Desde cero', 1, 1, 20, 32, 1600, 4.70, JSON_ARRAY('HTML, CSS, JavaScript', 'Node.js básico'), JSON_ARRAY('Astro setup', 'Islands architecture', 'SSG y SSR', 'Layouts', 'Rutas dinámicas', 'SEO', 'Performance', 'Deploy'), JSON_OBJECT('modulos', JSON_ARRAY(JSON_OBJECT('nombre', 'Fundamentos', 'lecciones', JSON_ARRAY('Setup', 'Pages', 'Layouts')), JSON_OBJECT('nombre', 'Contenido', 'lecciones', JSON_ARRAY('Markdown', 'Colecciones', 'SEO')), JSON_OBJECT('nombre', 'Deploy', 'lecciones', JSON_ARRAY('Vercel', 'Build', 'Variables')))), TRUE),
(5, 'Python Fullstack', 'python-fullstack', 'Django y FastAPI para desarrollo web completo con Python. Diseña modelos, APIs, autenticación y despliegues preparados para proyectos escalables.', 'https://images.unsplash.com/photo-1526374965328-7f5ae4e8b08f?w=500', 54.99, 'Intermedio', 2, 2, 40, 52, 2100, 4.80, JSON_ARRAY('Python fundamentals', 'SQL básico'), JSON_ARRAY('Django ORM', 'FastAPI', 'Autenticación', 'Validación', 'Testing', 'Deploy', 'Plantillas', 'Optimización'), JSON_OBJECT('modulos', JSON_ARRAY(JSON_OBJECT('nombre', 'Django', 'lecciones', JSON_ARRAY('Models', 'Views', 'Admin')), JSON_OBJECT('nombre', 'FastAPI', 'lecciones', JSON_ARRAY('Routes', 'Pydantic', 'Docs')), JSON_OBJECT('nombre', 'Producción', 'lecciones', JSON_ARRAY('Gunicorn', 'Docker', 'Logs')))), TRUE),
(6, 'Docker & Kubernetes', 'docker-kubernetes', 'Domina containerización y orquestación con Docker, docker-compose, Kubernetes, servicios y despliegue cloud. Esencial para DevOps y equipos modernos.', 'https://images.unsplash.com/photo-1558769132-cb1aea458c5e?w=500', 59.99, 'Avanzado', 3, 3, 36, 48, 1800, 4.70, JSON_ARRAY('Linux básico', 'Networking', 'Git'), JSON_ARRAY('Dockerfiles', 'Images y containers', 'Compose', 'Kubernetes pods', 'Services', 'Deployments', 'CI/CD', 'Monitoring'), JSON_OBJECT('modulos', JSON_ARRAY(JSON_OBJECT('nombre', 'Docker', 'lecciones', JSON_ARRAY('Images', 'Containers', 'Volumes')), JSON_OBJECT('nombre', 'Kubernetes', 'lecciones', JSON_ARRAY('Pods', 'Services', 'ConfigMaps')), JSON_OBJECT('nombre', 'Cloud', 'lecciones', JSON_ARRAY('Registry', 'Deploy', 'Logs')))), TRUE),
(7, 'Tailwind CSS Masterclass', 'tailwind-css-masterclass', 'Crea interfaces profesionales con Tailwind CSS, responsive design, dark mode, animaciones y sistemas de componentes mantenibles.', 'https://images.unsplash.com/photo-1561070791-2526d30994b5?w=500', 24.99, 'Intermedio', 1, 4, 16, 28, 900, 4.60, JSON_ARRAY('HTML y CSS', 'Responsive design'), JSON_ARRAY('Utility-first', 'Responsive', 'Dark mode', 'Animaciones', 'Config custom', 'Componentes', 'Accesibilidad', 'Performance'), JSON_OBJECT('modulos', JSON_ARRAY(JSON_OBJECT('nombre', 'Fundamentos', 'lecciones', JSON_ARRAY('Utilities', 'Responsive', 'States')), JSON_OBJECT('nombre', 'Sistema visual', 'lecciones', JSON_ARRAY('Theme', 'Plugins', 'Dark mode')), JSON_OBJECT('nombre', 'Proyectos', 'lecciones', JSON_ARRAY('Landing', 'Dashboard', 'Ecommerce')))), TRUE),
(8, 'Git & GitHub Pro', 'git-github-pro', 'Control de versiones profesional con ramas, pull requests, resolución de conflictos, GitHub Actions y workflows de equipo.', 'https://images.unsplash.com/photo-1552664730-d307ca884978?w=500', 19.99, 'Desde cero', 3, 3, 14, 24, 1200, 4.70, JSON_ARRAY('Terminal básica'), JSON_ARRAY('Commits claros', 'Branching', 'Merge conflicts', 'Pull requests', 'Code review', 'Actions', 'Git flow', 'Releases'), JSON_OBJECT('modulos', JSON_ARRAY(JSON_OBJECT('nombre', 'Git básico', 'lecciones', JSON_ARRAY('Init', 'Add', 'Commit')), JSON_OBJECT('nombre', 'Colaboración', 'lecciones', JSON_ARRAY('Branches', 'PRs', 'Reviews')), JSON_OBJECT('nombre', 'CI/CD', 'lecciones', JSON_ARRAY('Actions', 'Checks', 'Deploy')))), TRUE),
(9, 'SQL & Bases de Datos', 'sql-bases-de-datos', 'MySQL y PostgreSQL desde diseño relacional hasta queries avanzadas, índices, transacciones y optimización.', 'https://images.unsplash.com/photo-1526374965328-7f5ae4e8b08f?w=500', 29.99, 'Desde cero', 2, 2, 24, 36, 3100, 4.90, JSON_ARRAY('Conceptos de tablas', 'Relaciones'), JSON_ARRAY('SELECT', 'JOINs', 'Subqueries', 'Transacciones', 'Índices', 'EXPLAIN', 'Normalización', 'Backups'), JSON_OBJECT('modulos', JSON_ARRAY(JSON_OBJECT('nombre', 'Consultas', 'lecciones', JSON_ARRAY('SELECT', 'WHERE', 'ORDER')), JSON_OBJECT('nombre', 'Relaciones', 'lecciones', JSON_ARRAY('JOIN', 'FK', '3NF')), JSON_OBJECT('nombre', 'Performance', 'lecciones', JSON_ARRAY('Indexes', 'EXPLAIN', 'Locks')))), TRUE),
(10, 'HTML & CSS desde Cero', 'html-css-desde-cero', 'Fundamentos del desarrollo web con HTML5 semántico, CSS moderno, flexbox, grid, responsive design y accesibilidad.', 'https://images.unsplash.com/photo-1633356122544-f134324ef6db?w=500', 0.00, 'Desde cero', 1, 4, 18, 30, 900, 4.60, JSON_ARRAY('Ninguno'), JSON_ARRAY('HTML semántico', 'CSS base', 'Flexbox', 'Grid', 'Responsive', 'Formularios', 'Accesibilidad', 'Publicación'), JSON_OBJECT('modulos', JSON_ARRAY(JSON_OBJECT('nombre', 'HTML', 'lecciones', JSON_ARRAY('Tags', 'Forms', 'Semantics')), JSON_OBJECT('nombre', 'CSS', 'lecciones', JSON_ARRAY('Box model', 'Flexbox', 'Grid')), JSON_OBJECT('nombre', 'Proyecto', 'lecciones', JSON_ARRAY('Portfolio', 'Landing', 'Responsive')))), TRUE),
(11, 'React Native Apps', 'react-native-apps', 'Desarrolla apps iOS y Android con React Native y Expo. Incluye navegación, almacenamiento, permisos, rendimiento y publicación.', 'https://images.unsplash.com/photo-1607252650355-50742f54bff1?w=500', 49.99, 'Intermedio', 4, 1, 32, 44, 2400, 4.80, JSON_ARRAY('React fundamentals', 'JavaScript ES6+'), JSON_ARRAY('Expo setup', 'Navegación', 'State management', 'Camera', 'Location', 'Storage', 'Performance', 'Publicación'), JSON_OBJECT('modulos', JSON_ARRAY(JSON_OBJECT('nombre', 'Expo', 'lecciones', JSON_ARRAY('Setup', 'Components', 'Styles')), JSON_OBJECT('nombre', 'Features', 'lecciones', JSON_ARRAY('Permissions', 'Camera', 'Location')), JSON_OBJECT('nombre', 'Stores', 'lecciones', JSON_ARRAY('TestFlight', 'Play Store', 'Builds')))), TRUE),
(12, 'UI/UX Design Fundamentals', 'ui-ux-design-fundamentals', 'Principios de diseño, investigación de usuarios, prototipado, Figma, accesibilidad y sistemas visuales aplicados a productos digitales.', 'https://images.unsplash.com/photo-1561070791-2526d30994b5?w=500', 39.99, 'Desde cero', 5, 4, 26, 38, 900, 4.60, JSON_ARRAY('Curiosidad por producto', 'Navegador'), JSON_ARRAY('Design thinking', 'Color', 'Tipografía', 'Wireframes', 'Prototipos', 'Figma', 'Accesibilidad', 'Case study'), JSON_OBJECT('modulos', JSON_ARRAY(JSON_OBJECT('nombre', 'UX', 'lecciones', JSON_ARRAY('Research', 'Personas', 'Flows')), JSON_OBJECT('nombre', 'UI', 'lecciones', JSON_ARRAY('Color', 'Typography', 'Components')), JSON_OBJECT('nombre', 'Figma', 'lecciones', JSON_ARRAY('Auto layout', 'Prototype', 'Handoff')))), TRUE);
INSERT INTO posts (title, slug, excerpt, content, cover_image_url, author_id, category, tags, read_time_minutes, is_published, published_at) VALUES
('Guía Completa: Hooks en React', 'guia-completa-hooks-react', 'Entender hooks cambió la forma en que escribimos React. Descubre useState, useEffect, useContext y custom hooks.', '<h2>Introducción a los Hooks</h2><p>Los hooks revolucionaron React porque permiten usar estado y efectos en componentes funcionales. En una plataforma de cursos, esta ventaja se nota al controlar formularios, carrito, filtros, autenticación y datos remotos sin convertir cada pantalla en una clase enorme.</p><p>useState resuelve estado local, useEffect coordina sincronización con APIs y useContext permite compartir información cuando realmente tiene sentido. La clave profesional es no abusar de ellos: si un hook mezcla llamadas HTTP, validación, renderizado y navegación, deja de ayudar. Un custom hook debe encapsular una responsabilidad clara y devolver un contrato estable.</p><p>Los hooks también obligan a pensar en dependencias. Un array mal definido puede provocar peticiones infinitas o datos obsoletos. Por eso conviene separar cálculos derivados, handlers y efectos externos. Con práctica, los hooks convierten React en una herramienta más expresiva y mantenible.</p><h2>Conclusión</h2><p>Dominar hooks no es memorizar APIs, sino saber cuándo usarlas y cómo combinarlas sin crear deuda técnica.</p>', 'https://images.unsplash.com/photo-1633356122544-f134324ef6db?w=500', 1, 'React', JSON_ARRAY('react', 'hooks', 'javascript'), 8, TRUE, NOW()),
('TypeScript vs JavaScript: cuál elegir', 'typescript-vs-javascript', 'TypeScript añade tipos a JavaScript, pero también exige disciplina. Comparamos ventajas, costes y escenarios reales.', '<h2>TypeScript en proyectos reales</h2><p>JavaScript permite avanzar rápido, pero en proyectos con muchas pantallas los contratos implícitos acaban costando tiempo. TypeScript añade una capa de seguridad que ayuda a detectar errores antes del despliegue y documenta cómo viajan los datos entre backend y frontend.</p><p>En una aplicación e-learning, tipos como Course, Instructor, User y Order son parte del dominio. Si están bien definidos, el editor guía al equipo y reduce bugs. La desventaja es la curva inicial y la necesidad de compilar, pero el coste suele compensar cuando hay API, formularios, carrito y roles.</p><p>No hace falta usar tipos complejos para todo. La mejor estrategia empieza por tipar respuestas, props y estados críticos. Después se añaden generics o unions donde aportan claridad real.</p><h2>Conclusión</h2><p>Para CoderUp, TypeScript es una elección defendible porque mejora mantenibilidad y reduce errores de integración.</p>', 'https://images.unsplash.com/photo-1516321318423-f06f70d504f0?w=500', 1, 'TypeScript', JSON_ARRAY('typescript', 'javascript', 'tipos'), 7, TRUE, NOW()),
('CSS Grid: la guía definitiva', 'css-grid-guia-definitiva', 'CSS Grid revolucionó el layout web. Aprende a crear estructuras complejas sin depender de frameworks pesados.', '<h2>Layout bidimensional</h2><p>CSS Grid permite controlar filas y columnas al mismo tiempo, algo esencial para catálogos, dashboards y páginas de detalle. Mientras flexbox brilla en una dimensión, grid ofrece una estructura más clara cuando se combinan sidebar, contenido principal y bloques repetidos.</p><p>Una buena grilla empieza por definir el contenedor: columnas, gaps y comportamiento responsive. En mobile puede ser una columna; en desktop puede pasar a tres columnas sin duplicar HTML. Esto mantiene la semántica y mejora accesibilidad.</p><p>Grid también ayuda a evitar layouts frágiles. En vez de empujar elementos con márgenes arbitrarios, se colocan en áreas. Eso facilita mantener el diseño cuando cambian textos, imágenes o tarjetas.</p><h2>Conclusión</h2><p>CSS Grid no sustituye a todo, pero es una herramienta central para interfaces modernas y limpias.</p>', 'https://images.unsplash.com/photo-1561070791-2526d30994b5?w=500', 4, 'CSS', JSON_ARRAY('css', 'grid', 'layout'), 9, TRUE, NOW()),
('API REST: mejores prácticas', 'api-rest-mejores-practicas', 'Diseña APIs REST profesionales con versionado, paginación, errores consistentes y seguridad.', '<h2>Contratos claros</h2><p>Una API REST no es solo una colección de archivos PHP. Es un contrato entre cliente y servidor. Las rutas deben ser previsibles, las respuestas JSON consistentes y los errores útiles sin exponer información sensible.</p><p>En CoderUp, endpoints como cursos, posts, instructores, cupones y órdenes deben devolver estructuras estables. El frontend no debería adivinar si la lista viene en data, courses o result. Unificar formatos reduce código condicional y evita errores durante la defensa.</p><p>La seguridad se apoya en validación, prepared statements y tokens. También importan los códigos HTTP: 400 para datos inválidos, 401 para falta de autenticación, 404 para recursos inexistentes y 500 solo para errores inesperados.</p><h2>Conclusión</h2><p>Una API defendible falla bien, se documenta rápido y permite evolucionar el producto.</p>', 'https://images.unsplash.com/photo-1517694712202-14dd9538aa97?w=500', 2, 'Backend', JSON_ARRAY('api', 'rest', 'backend'), 10, TRUE, NOW()),
('Git Flow: workflow para equipos', 'git-flow-workflow-equipos', 'Un workflow consistente en Git evita conflictos y mantiene el historial útil para revisar decisiones.', '<h2>Más que subir código</h2><p>Git documenta cómo evoluciona un proyecto. En un TFG, un historial claro demuestra iteración, correcciones y madurez técnica. Commits pequeños y mensajes descriptivos ayudan a explicar qué se hizo y por qué.</p><p>Git Flow propone ramas para features, releases y hotfixes. En proyectos individuales puede simplificarse, pero la idea central sigue siendo válida: aislar cambios, revisar antes de mezclar y mantener main desplegable.</p><p>Antes de commitear conviene revisar diff, ejecutar build y comprobar que no se suben secretos. Con despliegues automáticos, cada push puede afectar producción, así que validar localmente es parte del trabajo profesional.</p><h2>Conclusión</h2><p>Git bien usado convierte el repositorio en una evidencia técnica del proceso.</p>', 'https://images.unsplash.com/photo-1552664730-d307ca884978?w=500', 3, 'Git', JSON_ARRAY('git', 'workflow', 'devops'), 8, TRUE, NOW()),
('Docker para principiantes', 'docker-para-principiantes', 'Containerización simplificada: Dockerfile, imágenes, contenedores, volúmenes y docker-compose.', '<h2>Entornos reproducibles</h2><p>Docker reduce el clásico problema de que una aplicación funciona solo en una máquina. Una imagen define dependencias, versión de runtime y comando de arranque. Eso permite que desarrollo, testing y producción se parezcan mucho más.</p><p>Un Dockerfile debe ser claro y pequeño. Cada instrucción crea capas, por lo que conviene copiar dependencias antes que código cuando sea posible. docker-compose facilita levantar servicios relacionados como frontend, backend y base de datos.</p><p>En producción, Docker ayuda a desplegar de forma repetible, pero no sustituye a logs, variables de entorno ni migraciones. Hay que saber observar qué ocurre dentro del contenedor.</p><h2>Conclusión</h2><p>Docker es una base excelente para DevOps práctico y despliegues más fiables.</p>', 'https://images.unsplash.com/photo-1558769132-cb1aea458c5e?w=500', 3, 'DevOps', JSON_ARRAY('docker', 'containers', 'devops'), 8, TRUE, NOW()),
('Accesibilidad web práctica', 'accesibilidad-web-practica', 'WCAG aplicado a formularios, navegación, contraste, foco visible y mensajes de error.', '<h2>Accesibilidad como calidad</h2><p>Una web accesible no es una versión especial, es una web bien construida. Labels, foco visible, contraste suficiente y mensajes de error claros ayudan a todos los usuarios, no solo a quienes usan lector de pantalla.</p><p>En una plataforma de cursos, los formularios de login, registro, checkout y recuperación de contraseña son críticos. Cada input debe tener etiqueta, los errores deben ser comprensibles y los botones deben indicar estados de carga o deshabilitado.</p><p>La navegación por teclado también debe funcionar. Si un usuario no puede llegar al carrito, aplicar cupón o enviar un formulario sin ratón, el flujo está incompleto.</p><h2>Conclusión</h2><p>WCAG aporta criterios objetivos para defender que la interfaz es profesional y usable.</p>', 'https://images.unsplash.com/photo-1581291518857-4e27b48ff24e?w=500', 4, 'UX', JSON_ARRAY('accesibilidad', 'wcag', 'ux'), 7, TRUE, NOW()),
('MySQL para ecommerce educativo', 'mysql-ecommerce-educativo', 'Cómo modelar usuarios, cursos, órdenes, items, cupones e inscripciones con integridad referencial.', '<h2>Datos que sostienen el producto</h2><p>Un ecommerce educativo necesita más que una tabla de cursos. Usuarios, órdenes, items, cupones e inscripciones forman un flujo completo. Cada compra debe conservar precio histórico, código aplicado y cursos desbloqueados.</p><p>MySQL permite expresar esas relaciones con foreign keys y tablas normalizadas. order_items separa los cursos comprados de la orden, enrollments registra el acceso posterior y coupons permite reglas comerciales sin tocar frontend.</p><p>Las transacciones son esenciales: crear orden, items e inscripciones debe ocurrir como una sola operación. Si algo falla, se revierte para no dejar datos a medias.</p><h2>Conclusión</h2><p>Un modelo relacional claro convierte el checkout en una funcionalidad defendible y auditable.</p>', 'https://images.unsplash.com/photo-1544383835-bda2bc66a55d?w=500', 2, 'Bases de Datos', JSON_ARRAY('mysql', 'sql', 'ecommerce'), 8, TRUE, NOW());
